        return new LoadedGeneration(generation, classLoader, factory.open());
    }

    long generation() {
        return generation;
    }

    PluginModule module() {
        return module;
    }

    @Override
    public void close() throws Exception {
        module.close();
        classLoader.close();
    }
}
